**Path:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775385272687-3v2azl/packages/next/geo.js`

This follows the `server.js` pattern exactly: a `serverExports` object, `module.exports`, and individual `exports.*` lines for named ESM-style imports.

```javascript
const geoExports = {
  geo: require('next/dist/server/web/spec-extension/geo').geo,
  geoFromHeaders: require('next/dist/server/web/spec-extension/geo')
    .geoFromHeaders,
  isInRegion: require('next/dist/server/web/spec-extension/geo').isInRegion,
  geoDistance: require('next/dist/server/web/spec-extension/geo').geoDistance,
  COUNTRY_NAMES: require('next/dist/server/web/spec-extension/geo')
    .COUNTRY_NAMES,
}

// https://nodejs.org/api/esm.html#commonjs-namespaces
module.exports = geoExports

// make import { xxx } from 'next/geo' work
exports.geo = geoExports.geo
exports.geoFromHeaders = geoExports.geoFromHeaders
exports.isInRegion = geoExports.isInRegion
exports.geoDistance = geoExports.geoDistance
exports.COUNTRY_NAMES = geoExports.COUNTRY_NAMES
```

**Why this structure:** The dual `module.exports` + `exports.*` pattern is required because Node.js ESM interop with CommonJS treats `module.exports` as the default export but does not automatically expose its properties as named exports. The explicit `exports.*` lines enable `import { geo } from 'next/geo'` to work correctly.

