    expect(geoDistance(40.7128, -74.006, 40.7128, -74.006)).toBe(0)
  })

  it('computes distance between New York and London', () => {
    // NY: 40.7128 N, 74.0060 W  London: 51.5074 N, 0.1278 W
    // Known distance: ~5570 km
    const d = geoDistance(40.7128, -74.006, 51.5074, -0.1278)
    expect(d).toBeGreaterThan(5500)
    expect(d).toBeLessThan(5600)
  })

  it('computes distance between Tokyo and Sydney', () => {
    // Tokyo: 35.6762 N, 139.6503 E  Sydney: 33.8688 S, 151.2093 E
    // Known distance: ~7823 km
    const d = geoDistance(35.6762, 139.6503, -33.8688, 151.2093)
    expect(d).toBeGreaterThan(7750)
    expect(d).toBeLessThan(7900)
  })

  it('computes antipodal distance (half circumference)', () => {
