/**
 * Geolocation helpers for use in middleware and edge functions.
 *
 * Extracts location data from common CDN/proxy headers
 * (Vercel, Cloudflare) and provides distance calculation utilities.
 */

export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

function extractGeoFromHeaders(headers: Headers): Geo {
  const city = headers.get('x-vercel-ip-city') || undefined
  const countryCode =
    headers.get('x-vercel-ip-country') ||
    headers.get('cf-ipcountry') ||
    undefined
  const region = headers.get('x-vercel-ip-country-region') || undefined
  const latitude = headers.get('x-vercel-ip-latitude') || undefined
  const longitude = headers.get('x-vercel-ip-longitude') || undefined
  const timezone = headers.get('x-vercel-ip-timezone') || undefined

  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()] || undefined
    : undefined

  return {
    city,
    country,
    countryCode,
    region,
    latitude,
    longitude,
    timezone,
  }
}

export function geo(req: { headers: Headers }): Geo {
  return extractGeoFromHeaders(req.headers)
}

export function geoFromHeaders(headers: Headers): Geo {
  return extractGeoFromHeaders(headers)
}

export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) {
    return false
  }
  const code = geoData.countryCode.toUpperCase()
  return regions.some((region) => region.toUpperCase() === code)
}

function toRadians(degrees: number): number {
  return (degrees * Math.PI) / 180
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const EARTH_RADIUS_KM = 6371

  const lat1Rad = toRadians(parseFloat(lat1))
  const lat2Rad = toRadians(parseFloat(lat2))
  const deltaLat = toRadians(parseFloat(lat2) - parseFloat(lat1))
  const deltaLon = toRadians(parseFloat(lon2) - parseFloat(lon1))

  const a =
    Math.sin(deltaLat / 2) * Math.sin(deltaLat / 2) +
    Math.cos(lat1Rad) *
      Math.cos(lat2Rad) *
      Math.sin(deltaLon / 2) *
      Math.sin(deltaLon / 2)

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

  return EARTH_RADIUS_KM * c
}

const geoExports = {
  geo: require('next/dist/server/web/spec-extension/geo').geo,
  geoFromHeaders:
    require('next/dist/server/web/spec-extension/geo').geoFromHeaders,
  isInRegion: require('next/dist/server/web/spec-extension/geo').isInRegion,
  geoDistance: require('next/dist/server/web/spec-extension/geo').geoDistance,
}

// https://nodejs.org/api/esm.html#commonjs-namespaces
// When importing CommonJS modules, the module.exports object is provided as the default export
module.exports = geoExports

// make import { xxx } from 'next/geo' work
exports.geo = geoExports.geo
exports.geoFromHeaders = geoExports.geoFromHeaders
exports.isInRegion = geoExports.isInRegion
exports.geoDistance = geoExports.geoDistance

