import { geo, geoFromHeaders, isInRegion, geoDistance } from './packages/next/src/server/web/spec-extension/geo.ts'
import assert from 'node:assert'

// Test 1: geo() with Vercel headers
{
  const headers = new Headers({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })
  const result = geo({ headers })
  assert.strictEqual(result.city, 'San Francisco')
  assert.strictEqual(result.countryCode, 'US')
  assert.strictEqual(result.country, 'United States')
  assert.strictEqual(result.region, 'CA')
  assert.strictEqual(result.latitude, '37.7749')
  assert.strictEqual(result.longitude, '-122.4194')
  assert.strictEqual(result.timezone, 'America/Los_Angeles')
  console.log('✓ geo() with Vercel headers')
}

// Test 2: missing headers return undefined
{
  const result = geo({ headers: new Headers() })
  assert.strictEqual(result.city, undefined)
  assert.strictEqual(result.countryCode, undefined)
  assert.strictEqual(result.country, undefined)
  assert.strictEqual(result.region, undefined)
  assert.strictEqual(result.latitude, undefined)
  assert.strictEqual(result.longitude, undefined)
  assert.strictEqual(result.timezone, undefined)
  console.log('✓ Missing headers return undefined')
}

// Test 3: geoFromHeaders() with Cloudflare fallback
{
  const headers = new Headers({ 'cf-ipcountry': 'DE' })
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'DE')
  assert.strictEqual(result.country, 'Germany')
  console.log('✓ geoFromHeaders() with Cloudflare fallback')
}

// Test 4: Vercel preferred over Cloudflare
{
  const headers = new Headers({
    'x-vercel-ip-country': 'FR',
    'cf-ipcountry': 'DE',
  })
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'FR')
  assert.strictEqual(result.country, 'France')
  console.log('✓ Vercel preferred over Cloudflare')
}

// Test 5: isInRegion matching
{
  assert.strictEqual(isInRegion({ countryCode: 'US' }, ['US', 'CA', 'GB']), true)
  assert.strictEqual(isInRegion({ countryCode: 'JP' }, ['US', 'CA', 'GB']), false)
  assert.strictEqual(isInRegion({ countryCode: 'us' }, ['US', 'CA']), true) // case-insensitive
  assert.strictEqual(isInRegion({ countryCode: 'US' }, ['us', 'ca']), true)
  assert.strictEqual(isInRegion({}, ['US', 'CA']), false) // no countryCode
  assert.strictEqual(isInRegion({ countryCode: 'US' }, []), false) // empty regions
  console.log('✓ isInRegion()')
}

// Test 6: geoDistance (NYC to London ~5570 km)
{
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(distance > 5520, `Expected >5520, got ${distance}`)
  assert.ok(distance < 5620, `Expected <5620, got ${distance}`)
  console.log(`✓ geoDistance() NYC to London = ${distance.toFixed(1)} km`)
}

// Test 7: geoDistance same point = 0
{
  const distance = geoDistance('40.7128', '-74.0060', '40.7128', '-74.0060')
  assert.strictEqual(distance, 0)
  console.log('✓ geoDistance() same point = 0')
}

// Test 8: country name lookup for all 10 codes
{
  const expected: Record<string, string> = {
    US: 'United States', GB: 'United Kingdom', DE: 'Germany',
    FR: 'France', JP: 'Japan', CN: 'China',
    IN: 'India', BR: 'Brazil', AU: 'Australia', CA: 'Canada',
  }
  for (const [code, name] of Object.entries(expected)) {
    const headers = new Headers({ 'x-vercel-ip-country': code })
    const result = geo({ headers })
    assert.strictEqual(result.country, name, `${code} -> ${name}`)
  }
  console.log('✓ Country name lookup for all 10 codes')
}

// Test 9: unknown country code returns undefined country name
{
  const headers = new Headers({ 'x-vercel-ip-country': 'ZZ' })
  const result = geo({ headers })
  assert.strictEqual(result.countryCode, 'ZZ')
  assert.strictEqual(result.country, undefined)
  console.log('✓ Unknown country code returns undefined country')
}

console.log('\nAll tests passed! ✅')
EOFSCRIPT

